module top_module (
    input clk,
    input reset,
    output reg [5:0] q
);
  wire _tap_clk = clk & {1{1'b1}};


    // Fibonacci LFSR logic
    always @(posedge clk) begin
        if (reset)
            q <= 6'b000001;
        else
            q <= {q[4:0], q[5] ^ q[4]};
    end

endmodule
